import { jest } from '@jest/globals';
import MistralClient from '../src/ai/MistralClient.js';

describe('MistralClient', () => {
  describe('Constructor', () => {
    it('should throw error without API key', () => {
      expect(() => new MistralClient()).toThrow('API key is required');
    });

    it('should throw error with null API key', () => {
      expect(() => new MistralClient(null)).toThrow('API key is required');
    });

    it('should throw error with empty API key', () => {
      expect(() => new MistralClient('')).toThrow('API key is required');
    });

    it('should accept custom options', () => {
      const client = new MistralClient('test-api-key', {
        model: 'mistral-small',
        maxTokens: 2048,
        temperature: 0.5,
      });

      expect(client.model).toBe('mistral-small');
      expect(client.maxTokens).toBe(2048);
      expect(client.temperature).toBe(0.5);
    });

    it('should use default options when not provided', () => {
      const client = new MistralClient('test-api-key');

      expect(client.model).toBe('mistral-large-latest');
      expect(client.maxTokens).toBe(4096);
      expect(client.temperature).toBe(0.7);
    });
  });

  describe('sendMessage validation', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
    });

    it('should throw error for non-array messages', async () => {
      await expect(client.sendMessage('not an array')).rejects.toThrow('Messages must be a non-empty array');
    });

    it('should throw error for empty messages array', async () => {
      await expect(client.sendMessage([])).rejects.toThrow('Messages must be a non-empty array');
    });

    it('should throw error for messages without role', async () => {
      const invalidMessages = [{ content: 'Hello' }];
      await expect(client.sendMessage(invalidMessages)).rejects.toThrow('Each message must have role and content');
    });

    it('should throw error for messages without content', async () => {
      const invalidMessages = [{ role: 'user' }];
      await expect(client.sendMessage(invalidMessages)).rejects.toThrow('Each message must have role and content');
    });
  });

  describe('streamResponse validation', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
    });

    it('should throw error for non-array messages', async () => {
      const onChunk = jest.fn();
      await expect(client.streamResponse('not an array', onChunk)).rejects.toThrow('Messages must be a non-empty array');
    });

    it('should throw error for empty messages array', async () => {
      const onChunk = jest.fn();
      await expect(client.streamResponse([], onChunk)).rejects.toThrow('Messages must be a non-empty array');
    });

    it('should throw error if onChunk is not a function', async () => {
      const messages = [{ role: 'user', content: 'Hi' }];
      await expect(client.streamResponse(messages, 'not-a-function')).rejects.toThrow('onChunk must be a function');
    });

    it('should throw error if onChunk is null', async () => {
      const messages = [{ role: 'user', content: 'Hi' }];
      await expect(client.streamResponse(messages, null)).rejects.toThrow('onChunk must be a function');
    });
  });

  describe('shouldRetry', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
    });

    it('should retry on rate limit errors', () => {
      expect(client.shouldRetry(new Error('Rate limit exceeded'))).toBe(true);
      expect(client.shouldRetry(new Error('429 Too Many Requests'))).toBe(true);
      expect(client.shouldRetry(new Error('rate limit'))).toBe(true);
    });

    it('should retry on network errors', () => {
      expect(client.shouldRetry(new Error('Network timeout'))).toBe(true);
      expect(client.shouldRetry(new Error('ECONNRESET'))).toBe(true);
      expect(client.shouldRetry(new Error('ECONNREFUSED'))).toBe(true);
      expect(client.shouldRetry(new Error('network error'))).toBe(true);
    });

    it('should retry on server errors', () => {
      expect(client.shouldRetry(new Error('500 Internal Server Error'))).toBe(true);
      expect(client.shouldRetry(new Error('502 Bad Gateway'))).toBe(true);
      expect(client.shouldRetry(new Error('503 Service Unavailable'))).toBe(true);
      expect(client.shouldRetry(new Error('504 Gateway Timeout'))).toBe(true);
    });

    it('should not retry on client errors', () => {
      expect(client.shouldRetry(new Error('400 Bad Request'))).toBe(false);
      expect(client.shouldRetry(new Error('Invalid input'))).toBe(false);
      expect(client.shouldRetry(new Error('404 Not Found'))).toBe(false);
    });

    it('should not retry on authentication errors', () => {
      expect(client.shouldRetry(new Error('401 Unauthorized'))).toBe(false);
      expect(client.shouldRetry(new Error('403 Forbidden'))).toBe(false);
    });
  });

  describe('calculateBackoff', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
    });

    it('should calculate exponential backoff with jitter', () => {
      const delay0 = client.calculateBackoff(0);
      const delay1 = client.calculateBackoff(1);
      const delay2 = client.calculateBackoff(2);
      
      // Check base delays with jitter (should be around base + 0-20% jitter)
      // Attempt 0: 1000ms base
      expect(delay0).toBeGreaterThanOrEqual(1000);
      expect(delay0).toBeLessThan(1200);
      
      // Attempt 1: 2000ms base
      expect(delay1).toBeGreaterThanOrEqual(2000);
      expect(delay1).toBeLessThan(2400);
      
      // Attempt 2: 4000ms base
      expect(delay2).toBeGreaterThanOrEqual(4000);
      expect(delay2).toBeLessThan(4800);
    });

    it('should add randomness (jitter) to backoff', () => {
      const delays = [];
      for (let i = 0; i < 10; i++) {
        delays.push(client.calculateBackoff(1));
      }
      
      // Check that not all delays are identical (jitter is working)
      const uniqueDelays = new Set(delays);
      expect(uniqueDelays.size).toBeGreaterThan(1);
    });
  });

  describe('sleep', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
    });

    it('should sleep for specified duration', async () => {
      const start = Date.now();
      await client.sleep(100);
      const elapsed = Date.now() - start;
      
      expect(elapsed).toBeGreaterThanOrEqual(95); // Allow small margin
      expect(elapsed).toBeLessThan(150);
    });
  });

  describe('registerTools', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
    });

    it('should register valid tool definitions', () => {
      const tools = [
        {
          type: 'function',
          function: {
            name: 'read_file',
            description: 'Read a file',
            parameters: {
              type: 'object',
              properties: {
                path: { type: 'string' },
              },
            },
          },
        },
      ];
      
      client.registerTools(tools);
      
      expect(client.tools).toEqual(tools);
      expect(client.tools.length).toBe(1);
    });

    it('should register multiple tools', () => {
      const tools = [
        {
          type: 'function',
          function: {
            name: 'read_file',
            description: 'Read a file',
          },
        },
        {
          type: 'function',
          function: {
            name: 'write_file',
            description: 'Write a file',
          },
        },
      ];
      
      client.registerTools(tools);
      
      expect(client.tools.length).toBe(2);
    });

    it('should throw error for non-array tools', () => {
      expect(() => client.registerTools('not-an-array')).toThrow('Tool definitions must be an array');
      expect(() => client.registerTools({})).toThrow('Tool definitions must be an array');
      expect(() => client.registerTools(null)).toThrow('Tool definitions must be an array');
    });

    it('should throw error for tools without type', () => {
      const invalidTools = [
        {
          function: {
            name: 'read_file',
            description: 'Read a file',
          },
        },
      ];
      
      expect(() => client.registerTools(invalidTools)).toThrow('Each tool must have type and function');
    });

    it('should throw error for tools without function property', () => {
      const invalidTools = [
        {
          type: 'function',
        },
      ];
      
      expect(() => client.registerTools(invalidTools)).toThrow('Each tool must have type and function');
    });

    it('should throw error for tools without function name', () => {
      const invalidTools = [
        {
          type: 'function',
          function: {
            description: 'Read a file',
          },
        },
      ];
      
      expect(() => client.registerTools(invalidTools)).toThrow('Each tool function must have name and description');
    });

    it('should throw error for tools without function description', () => {
      const invalidTools = [
        {
          type: 'function',
          function: {
            name: 'read_file',
          },
        },
      ];
      
      expect(() => client.registerTools(invalidTools)).toThrow('Each tool function must have name and description');
    });
  });

  describe('sendWithTools validation', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
    });

    it('should throw error for empty messages array', async () => {
      const tools = [
        {
          type: 'function',
          function: {
            name: 'read_file',
            description: 'Read a file',
          },
        },
      ];
      
      client.registerTools(tools);
      
      await expect(client.sendWithTools([])).rejects.toThrow('Messages must be a non-empty array');
    });

    it('should throw error if no tools are registered or provided', async () => {
      const messages = [{ role: 'user', content: 'Hello' }];
      
      await expect(client.sendWithTools(messages)).rejects.toThrow('No tools available');
    });
  });

  describe('streamWithTools validation', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
    });

    it('should throw error for empty messages array', async () => {
      const tools = [
        {
          type: 'function',
          function: {
            name: 'read_file',
            description: 'Read a file',
          },
        },
      ];
      
      client.registerTools(tools);
      const onChunk = jest.fn();
      const onToolCall = jest.fn();
      
      await expect(client.streamWithTools([], onChunk, onToolCall)).rejects.toThrow('Messages must be a non-empty array');
    });

    it('should throw error if onChunk is not a function', async () => {
      const tools = [
        {
          type: 'function',
          function: {
            name: 'read_file',
            description: 'Read a file',
          },
        },
      ];
      
      client.registerTools(tools);
      const messages = [{ role: 'user', content: 'Hi' }];
      
      await expect(client.streamWithTools(messages, 'not-a-function', jest.fn())).rejects.toThrow('onChunk must be a function');
    });

    it('should throw error if no tools are available', async () => {
      const messages = [{ role: 'user', content: 'Hi' }];
      const onChunk = jest.fn();
      const onToolCall = jest.fn();
      
      await expect(client.streamWithTools(messages, onChunk, onToolCall)).rejects.toThrow('No tools available');
    });
  });

  describe('retryWithBackoff', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
      // Mock sleep to avoid actual delays in tests
      jest.spyOn(client, 'sleep').mockResolvedValue();
    });

    it('should succeed on first attempt', async () => {
      const fn = jest.fn().mockResolvedValue('success');
      
      const result = await client.retryWithBackoff(fn, 3);
      
      expect(result).toBe('success');
      expect(fn).toHaveBeenCalledTimes(1);
      expect(client.sleep).not.toHaveBeenCalled();
    });

    it('should retry on retryable error', async () => {
      const fn = jest.fn()
        .mockRejectedValueOnce(new Error('Rate limit exceeded'))
        .mockResolvedValue('success');
      
      const result = await client.retryWithBackoff(fn, 3);
      
      expect(result).toBe('success');
      expect(fn).toHaveBeenCalledTimes(2);
      expect(client.sleep).toHaveBeenCalledTimes(1);
    });

    it('should not retry on authentication errors', async () => {
      const fn = jest.fn().mockRejectedValue(new Error('Authentication failed: Invalid API key'));
      
      await expect(client.retryWithBackoff(fn, 3)).rejects.toThrow('Authentication failed');
      expect(fn).toHaveBeenCalledTimes(1);
      expect(client.sleep).not.toHaveBeenCalled();
    });

    it('should throw after max retries', async () => {
      const fn = jest.fn().mockRejectedValue(new Error('Network error'));
      
      await expect(client.retryWithBackoff(fn, 2)).rejects.toThrow('Network error');
      expect(fn).toHaveBeenCalledTimes(3); // initial + 2 retries
      expect(client.sleep).toHaveBeenCalledTimes(2);
    });

    it('should retry multiple times before succeeding', async () => {
      const fn = jest.fn()
        .mockRejectedValueOnce(new Error('500 Internal Server Error'))
        .mockRejectedValueOnce(new Error('503 Service Unavailable'))
        .mockResolvedValue('success');
      
      const result = await client.retryWithBackoff(fn, 3);
      
      expect(result).toBe('success');
      expect(fn).toHaveBeenCalledTimes(3);
      expect(client.sleep).toHaveBeenCalledTimes(2);
    });
  });

  describe('handleRateLimit', () => {
    let client;

    beforeEach(() => {
      client = new MistralClient('test-api-key');
      jest.spyOn(client, 'sleep').mockResolvedValue();
    });

    it('should wait for retry-after header duration', async () => {
      const error = {
        response: {
          headers: {
            'retry-after': '30',
          },
        },
      };
      
      await client.handleRateLimit(error);
      
      expect(client.sleep).toHaveBeenCalledWith(30000);
    });

    it('should wait default 60 seconds if no retry-after header', async () => {
      const error = {
        response: {
          headers: {},
        },
      };
      
      await client.handleRateLimit(error);
      
      expect(client.sleep).toHaveBeenCalledWith(60000);
    });

    it('should wait default 60 seconds if no response', async () => {
      const error = {};
      
      await client.handleRateLimit(error);
      
      expect(client.sleep).toHaveBeenCalledWith(60000);
    });
  });
});
